insert into country_picks (country_code, flag, country_ko, country_en, country_zh, country_ja, rank_num, name_ko, name_en, name_zh, name_ja, score, popularity, reason_ko, reason_en, reason_zh, reason_ja, source_ko, source_en, source_zh, source_ja, source_url) values
('us', '🇺🇸', '미국', 'USA', '美国', 'アメリカ', 1, '농심 신라면', 'Nongshim Shin Ramyun', '农心辛拉面', '農心辛ラーメン', null, null, '미국 현지 공장에서 생산. 트랜스지방·MSG를 첨가하지 않아 건강을 중시하는 미국 소비자에게도 어필. 한국 라면의 대표 브랜드.', 'Produced at a local US factory. No trans fat or MSG added — appeals to health-conscious American consumers. The flagship Korean ramen brand.', '在美国本地工厂生产，不含反式脂肪和MSG，受注重健康的美国消费者青睐，是韩国拉面的代表品牌。', '米国現地工場で生産。トランス脂肪・MSG不使用で健康志向の米国消費者にもアピール。韓国ラーメンの代表ブランド。', 'College Inside(미주중앙일보) 편집 리스트', 'College Inside (Korea Daily US) editorial list', 'College Inside（美国中央日报）编辑推荐', 'College Inside（米国コリアデイリー）編集リスト', 'https://college.koreadaily.com/%EB%AF%B8%EA%B5%AD%EC%97%90%EC%84%9C-%EC%82%AC%EB%9E%91%EB%B0%9B%EB%8A%94-%ED%95%9C%EA%B5%AD%EB%9D%BC%EB%A9%B4-top-5/'),
('us', '🇺🇸', '미국', 'USA', '美国', 'アメリカ', 2, '농심 짜파게티 & 너구리', 'Nongshim Chapagetti & Neoguri', '农心炸酱意面＆貉子拉面', '農心チャパゲティ＆たぬきラーメン', null, null, '영화 〈기생충〉 속 ''짜파구리'' 조리법으로 화제가 된 이후 수출량이 120% 증가. 두 라면을 섞어 끓이는 방식이 미국에서도 유행.', 'Export volume jumped 120% after the ''Chapaguri'' recipe went viral in the film Parasite. The mix-and-cook method caught on in the US too.', '因电影《寄生虫》中的"炸酱乌冬"做法走红后出口量增加120%，两款拉面混煮的方式在美国也流行起来。', '映画『パラサイト』の「チャパグリ」レシピで話題になり輸出量が120%増加。2つを混ぜて調理する方法が米国でも流行。', 'College Inside(미주중앙일보) 편집 리스트', 'College Inside (Korea Daily US) editorial list', 'College Inside（美国中央日报）编辑推荐', 'College Inside（米国コリアデイリー）編集リスト', 'https://college.koreadaily.com/%EB%AF%B8%EA%B5%AD%EC%97%90%EC%84%9C-%EC%82%AC%EB%9E%91%EB%B0%9B%EB%8A%94-%ED%95%9C%EA%B5%AD%EB%9D%BC%EB%A9%B4-top-5/'),
('us', '🇺🇸', '미국', 'USA', '美国', 'アメリカ', 3, '삼양 불닭볶음면', 'Samyang Buldak Bokkeum Myeon', '三养火鸡炒面', 'サムヤン ブルダック炒め麺', null, null, '매운맛 챌린지 콘텐츠로 SNS에서 인기가 확산. 극강의 매운맛을 도전하는 문화가 미국 젊은층 사이에서 유행.', 'Spread through SNS spicy challenge content. The culture of taking on extreme heat caught on among young Americans.', '通过SNS辣味挑战内容广泛传播，挑战极辣的文化在美国年轻人中流行。', 'SNSの辛さチャレンジコンテンツで人気が拡散。極辛に挑む文化が米国の若者の間で流行。', 'College Inside(미주중앙일보) 편집 리스트', 'College Inside (Korea Daily US) editorial list', 'College Inside（美国中央日报）编辑推荐', 'College Inside（米国コリアデイリー）編集リスト', 'https://college.koreadaily.com/%EB%AF%B8%EA%B5%AD%EC%97%90%EC%84%9C-%EC%82%AC%EB%9E%91%EB%B0%9B%EB%8A%94-%ED%95%9C%EA%B5%AD%EB%9D%BC%EB%A9%B4-top-5/'),
('us', '🇺🇸', '미국', 'USA', '美国', 'アメリカ', 4, '오뚜기 진짬뽕', 'Ottogi Jin Jjamppong', '不倒翁真炒码面', 'オットギ ジンチャンポン', null, null, '해산물과 고춧가루가 들어간 진한 짬뽕 맛. 한때 신라면의 인기를 위협할 정도로 주목받은 제품.', 'Rich jjamppong flavor with seafood and red pepper. Once gained enough attention to rival Shin Ramyun''s dominance.', '含海鲜和辣椒粉的浓郁炒码面口味，曾受到足以威胁辛拉面地位的高度关注。', '海鮮と唐辛子の濃いチャンポン味。一時は辛ラーメンの人気を脅かすほど注目された製品。', 'College Inside(미주중앙일보) 편집 리스트', 'College Inside (Korea Daily US) editorial list', 'College Inside（美国中央日报）编辑推荐', 'College Inside（米国コリアデイリー）編集リスト', 'https://college.koreadaily.com/%EB%AF%B8%EA%B5%AD%EC%97%90%EC%84%9C-%EC%82%AC%EB%9E%91%EB%B0%9B%EB%8A%94-%ED%95%9C%EA%B5%AD%EB%9D%BC%EB%A9%B4-top-5/'),
('us', '🇺🇸', '미국', 'USA', '美国', 'アメリカ', 5, '팔도 치즈라면', 'Paldo Cheese Ramen', '八道芝士拉面', 'パルド チーズラーメン', null, null, '치즈의 고소함과 매운 소스의 조합이 특징. 매운맛을 부드럽게 중화해주는 치즈 풍미가 미국 소비자 입맛에 맞음.', 'Features the combination of nutty cheese and spicy sauce. The cheese flavor softens the heat in a way that suits American palates.', '奶酪香浓与辣酱的组合为特色，奶酪风味柔和了辣味，符合美国消费者口味。', 'チーズのコクと辛いソースの組み合わせが特徴。チーズ風味が辛さをマイルドにし、米国消費者の口に合う。', 'College Inside(미주중앙일보) 편집 리스트', 'College Inside (Korea Daily US) editorial list', 'College Inside（美国中央日报）编辑推荐', 'College Inside（米国コリアデイリー）編集リスト', 'https://college.koreadaily.com/%EB%AF%B8%EA%B5%AD%EC%97%90%EC%84%9C-%EC%82%AC%EB%9E%91%EB%B0%9B%EB%8A%94-%ED%95%9C%EA%B5%AD%EB%9D%BC%EB%A9%B4-top-5/');
